// // This is a D Flip-Flop with an active-high synchronous reset. The flip-flop should latch the input data on the falling edge of the clock.
module d_flip_flop(
    input clk,          // Clock signal.
    input rst_n,        // Active-low synchronous reset.
    input d,            // Data input.
    output reg q        // Data output.
);

// Flip-Flop logic
always @(posedge clk) begin
    if (!rst_n) begin
        q <= 0;
    end else begin
        q <= d;
    end
end

endmodule
